def get_user(username):
    return USERS.get(username)

def verify_password(user, password):
    return check_password_hash(user["password_hash"], password)

def _normalize_base32_secret(secret):
    secret = secret.strip().replace(" ", "").upper()
    padding = "=" * ((8 - len(secret) % 8) % 8)
    return secret + padding

def generate_totp(secret, interval=30, digits=6, for_time=None):
    if for_time is None:
        for_time = int(time.time())
    counter = int(for_time // interval)
    key = base64.b32decode(_normalize_base32_secret(secret), casefold=True)
    msg = struct.pack(">Q", counter)
    digest = hmac.new(key, msg, hashlib.sha1).digest()
    offset = digest[-1] & 0x0F
    code = struct.unpack(">I", digest[offset:offset + 4])[0] & 0x7FFFFFFF
    return str(code % (10 ** digits)).zfill(digits)

def verify_totp(secret, otp, window=1, interval=30, digits=6):
    otp = str(otp).strip()
    now = int(time.time())
    for offset in range(-window, window + 1):
        candidate = generate_totp(secret, interval=interval, digits=digits, for_time=now + offset * interval)
        if secrets.compare_digest(candidate, otp):
            return True
    return False

